code.C:
#include <stdio.h>

int daysLeft(int n) {
    return 365 - n;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        if (scanf("%d", &n) != 1) break;
        printf("%d\n", daysLeft(n));
    }
    return 0;
}

